// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.PurchaseReceipt) predicate.PurchaseReceipt {
	return predicate.PurchaseReceipt(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.PurchaseReceipt) predicate.PurchaseReceipt {
	return predicate.PurchaseReceipt(sql.NotPredicates(p))
}
